import { test, expect } from '@playwright/test';

test('verify header links and targets on mobile', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002');

  // Verify header links on Home page
  const homeLink = page.getByRole('link', { name: 'Home' });
  const blogLink = page.getByRole('link', { name: 'blog', exact: true });
  const portfolioLink = page.getByRole('link', { name: 'portfolio', exact: true });
  const videosLink = page.getByRole('link', { name: 'videos', exact: true });
  const contactLink = page.getByRole('link', { name: 'contact', exact: true });

  // Check existence and href targets on Home page
  await expect(homeLink).toBeVisible(); // Missing: only 'okwasniewski' points to '/'
  await expect(blogLink).toHaveAttribute('href', '/blog'); // Fails: points to '/blgo'
  await expect(portfolioLink).toHaveAttribute('href', '/portfolio');
  await expect(videosLink).toHaveAttribute('href', '/videos');
  await expect(contactLink).toHaveAttribute('href', '/contact');

  // Navigate to 404 page (by following the broken blog link) to check header consistency
  await page.goto('http://localhost:3002/blgo');
  const contactLink404 = page.getByRole('link', { name: 'contact', exact: true });
  await expect(contactLink404).toHaveAttribute('href', '/contact'); // Fails: points to '/contcat'
});
